// @ts-check
/** @typedef {import('../../InvocationContext.js').InvocationContext} InvocationContext */

import { Command } from '../../../utils/Command.js'
import { CommandType } from '../../../utils/CommandType.js'
import { RuntimeName } from '../../../utils/RuntimeName.js'
import { handleResultWithAction } from './TypeParsingUtils.js'

/**
 * @param {InvocationContext} invocationContext
 * @returns {Date}
 */
export function parseDatetime(invocationContext) {
    const result = invocationContext.invokeInstanceMethod('timestamp').execute()
    return handleResultWithAction(result, (/** @type {any} */ timestamp) => {
        if (timestamp == null) throw new Error('timestamp returned null')
        return new Date(Number(timestamp) * 1000)
    })
}

/**
 * @param {InvocationContext} invocationContext
 * @returns {string}
 */
export function parseUUID(invocationContext) {
    const result = invocationContext.invokeInstanceMethod('__str__').execute()
    return handleResultWithAction(result, (/** @type {any} */ val) => String(val))
}

/** Inbound: Python result type string → JavaScript object */
export const PythonTypeParsingFunctions = new Map(/** @type {[string, (invocationContext: InvocationContext) => unknown][]} */ ([
    ['datetime.datetime', parseDatetime],
    ['uuid.UUID', parseUUID],
]))

/**
 * Outbound: JavaScript object → Command graph targeting the Python runtime
 * @type {Map<Function, (value: any) => Command>}
 */
export const PythonParsingArgument = new Map([
    [Date, (/** @type {Date} */ value) => new Command(RuntimeName.Python, CommandType.InvokeStaticMethod, [
        new Command(RuntimeName.Python, CommandType.GetType, ['datetime.datetime']),
        'fromtimestamp',
        value.getTime() / 1000,
    ])],
])
